// =============================================================================
// Platform Configuration Loader
// =============================================================================
// THIS FILE IS THE SOURCE OF TRUTH
// Copied to platform directories by scripts/prepare-frontend.sh
//
// Loads platform.json (platform-specific config) and firebase-config.json
// (environment-specific config generated by Terraform) and merges them into
// a single runtime configuration object.
// =============================================================================

const PlatformConfig = {
  _config: null,
  _firebaseConfig: null,

  /**
   * Load both platform.json and firebase-config.json.
   * Must be called before any other PlatformConfig method.
   * @returns {Object} The platform configuration object
   */
  async load() {
    try {
      const [platformRes, firebaseRes] = await Promise.all([
        fetch("platform.json"),
        fetch("firebase-config.json"),
      ]);

      if (!platformRes.ok) {
        throw new Error(
          `platform.json not found (HTTP ${platformRes.status}). Please ensure prepare-frontend.sh has been run.`
        );
      }
      if (!firebaseRes.ok) {
        throw new Error(
          `firebase-config.json not found (HTTP ${firebaseRes.status}). Please ensure terraform apply has been run.`
        );
      }

      this._config = await platformRes.json();
      this._firebaseConfig = await firebaseRes.json();

      console.log(
        "Platform configuration loaded:",
        this._config.platform
      );

      return this._config;
    } catch (error) {
      console.error("Failed to load configuration:", error);

      // Show user-friendly error
      const errorDiv = document.createElement("div");
      errorDiv.style.cssText =
        "position: fixed; top: 0; left: 0; right: 0; background: #dc3545; color: white; padding: 1rem; text-align: center; z-index: 9999;";
      errorDiv.innerHTML =
        "<strong>Configuration Error:</strong> " +
        error.message;
      document.body.prepend(errorDiv);

      throw error;
    }
  },

  /**
   * Get a top-level config value.
   * @param {string} key - e.g. 'platform', 'investigateEndpoint', 'emailRequired'
   */
  get(key) {
    return this._config?.[key];
  },

  /**
   * Get a UI config value.
   * @param {string} key - e.g. 'headerTitle', 'submitButtonText'
   */
  getUI(key) {
    return this._config?.ui?.[key];
  },

  /**
   * Get a content config value.
   * @param {string} key - e.g. 'folderName', 'userRole'
   */
  getContent(key) {
    return this._config?.content?.[key];
  },

  /**
   * Check if a feature flag is enabled.
   * @param {string} name - e.g. 'addressVerification'
   */
  hasFeature(name) {
    return this._config?.features?.[name] === true;
  },

  /** Get the API Gateway URL (from firebase-config.json) */
  get apiUrl() {
    return this._firebaseConfig?.apiUrl;
  },

  /** Get the Firebase SDK config object (from firebase-config.json) */
  get firebaseConfig() {
    const c = this._firebaseConfig;
    return c
      ? {
          apiKey: c.apiKey,
          authDomain: c.authDomain,
          projectId: c.projectId,
          storageBucket: c.storageBucket,
          messagingSenderId: c.messagingSenderId,
          appId: c.appId,
        }
      : null;
  },
};
